1	# Managed hosts: classic-laddie, johnny-walker, klaus-worker-0, makers-nix, weller
2	{
3	  description = "Cosmo: Fresh Start 2025";
4	
5	  inputs = {
6	    # The unstable branch is usually fine for desktops/home-servers,
7	    # but use "nixos-24.11" if you want rock-solid stability.
8	    nixpkgs.url = "github:nixos/nixpkgs/nixos-unstable";
9	
10	    agenix.url = "github:ryantm/agenix";
11	    agenix.inputs.nixpkgs.follows = "nixpkgs";
12	
13	    home-manager.url = "github:nix-community/home-manager";
14	    home-manager.inputs.nixpkgs.follows = "nixpkgs";
15	
16	    nixos-wsl.url = "github:nix-community/NixOS-WSL/main";
17	    nixos-wsl.inputs.nixpkgs.follows = "nixpkgs";
18	
19	    pre-commit-hooks = {
20	      url = "github:cachix/git-hooks.nix";
21	      inputs.nixpkgs.follows = "nixpkgs";
22	    };
23	
24	    nixos-generators = {
25	      url = "github:nix-community/nixos-generators";
26	      inputs.nixpkgs.follows = "nixpkgs";
27	    };
28	
29	    disko = {
30	      url = "github:nix-community/disko";
31	      inputs.nixpkgs.follows = "nixpkgs";
32	    };
33	
34	    klaus = {
35	      url = "github:patflynn/klaus";
36	      inputs.nixpkgs.follows = "nixpkgs";
37	    };
38	
39	    microvm = {
40	      url = "github:astro/microvm.nix";
41	      inputs.nixpkgs.follows = "nixpkgs";
42	    };
43	
44	    reel-life = {
45	      url = "github:gunk-dev/reel-life";
46	      inputs.nixpkgs.follows = "nixpkgs";
47	    };
48	
49	    github-relay = {
50	      url = "github:patflynn/github-relay";
51	      inputs.nixpkgs.follows = "nixpkgs";
52	    };
53	
54	    # Bare-git hosting module (valley-host) consumed by classic-laddie.
55	    the-valley = {
56	      url = "github:gunk-dev/the-valley";
57	      inputs.nixpkgs.follows = "nixpkgs";
58	    };
59	
60	    zen-browser.url = "github:0xc000022070/zen-browser-flake";
61	  };
62	
63	  outputs =
64	    {
65	      self,
66	      nixpkgs,
67	      home-manager,
68	      nixos-generators,
69	      agenix,
70	      pre-commit-hooks,
71	      klaus,
72	      microvm,
73	      reel-life,
74	      github-relay,
75	      ...
76	    }@inputs:
77	    let
78	      mkHome =
79	        {
80	          username,
81	          identity,
82	          baseModule,
83	          homeDirectory ? "/home/${username}",
84	        }:
85	        home-manager.lib.homeManagerConfiguration {
86	          pkgs = import nixpkgs {
87	            system = "x86_64-linux";
88	            config.allowUnfree = true;
89	          };
90	          extraSpecialArgs = { inherit inputs; };
91	          modules = [
92	            baseModule
93	            identity
94	            {
95	              home.username = username;
96	              home.homeDirectory = homeDirectory;
97	            }
98	          ];
99	        };
100	
101	      mkBootstrap =
102	        {
103	          system ? "x86_64-linux",
104	          hardware,
105	          disk ? null,
106	          hostName ? "nixos-bootstrap",
107	          hostId ? null,
108	          user ? "patrick",
109	          email ? "big.pat@gmail.com",
110	        }:
111	        nixpkgs.lib.nixosSystem {
112	          specialArgs = { inherit inputs; };
113	          modules = [
114	            { nixpkgs.hostPlatform = system; }
115	            hardware
116	            (if disk != null then disk else { })
117	            (if disk != null then inputs.disko.nixosModules.disko else { })
118	            ./modules/bootstrap.nix
119	            {
120	              networking.hostName = hostName;
121	              cosmo.user.default = user;
122	              cosmo.user.email = email;
123	            }
124	            (if hostId != null then { networking.hostId = hostId; } else { })
125	          ];
126	        };
127	    in
128	    {
129	      formatter.x86_64-linux = nixpkgs.legacyPackages.x86_64-linux.nixfmt-tree;
130	
131	      nixosConfigurations = {
132	        # Hostname: classic-laddie
133	        classic-laddie = nixpkgs.lib.nixosSystem {
134	          specialArgs = { inherit inputs; };
135	          modules = [
136	            { nixpkgs.hostPlatform = "x86_64-linux"; }
137	            ./hosts/classic-laddie/default.nix
138	            agenix.nixosModules.default
139	            microvm.nixosModules.host
140	            home-manager.nixosModules.home-manager
141	            (
142	              { config, ... }:
143	              {
144	                home-manager.useGlobalPkgs = true;
145	                home-manager.useUserPackages = true;
146	                home-manager.backupFileExtension = "backup";
147	                home-manager.extraSpecialArgs = { inherit inputs; };
148	                home-manager.users.${config.cosmo.user.default} = {
149	                  imports = [
150	                    ./home/server.nix
151	                    ./home/dev.nix
152	                    ./home/desktop.nix
153	                    ./home/identities/personal.nix
154	                    ./home/monitor-input.nix
155	                  ];
156	                  # Native (non-FHS) Antigravity IDE; unfree, allowed on this
157	                  # GPU host (hardware.nix sets nixpkgs.config.allowUnfree).
158	                  cosmo.antigravity.enable = true;
159	                  # Lock screen immediately on session start (auto-login is enabled)
160	                  wayland.windowManager.hyprland.settings.exec-once = [ "hyprlock" ];
161	                };
162	              }
163	            )
164	          ];
165	        };
166	
167	        # Bootstrap install target for classic-laddie (hostname: classic-laddie)
168	        classic-laddie-bootstrap = mkBootstrap {
169	          hardware = ./hosts/classic-laddie/hardware.nix;
170	          hostName = "classic-laddie";
171	          hostId = "8425e349";
172	        };
173	
174	        # Hostname: makers-nix
175	        makers-nix = nixpkgs.lib.nixosSystem {
176	          specialArgs = { inherit inputs; };
177	          modules = [
178	            { nixpkgs.hostPlatform = "x86_64-linux"; }
179	            ./hosts/makers-nix/default.nix
180	            inputs.nixos-wsl.nixosModules.wsl
181	            agenix.nixosModules.default
182	            home-manager.nixosModules.home-manager
183	            (
184	              { config, ... }:
185	              {
186	                home-manager.useGlobalPkgs = true;
187	                home-manager.useUserPackages = true;
188	                home-manager.backupFileExtension = "backup";
189	                home-manager.extraSpecialArgs = { inherit inputs; };
190	                home-manager.users.${config.cosmo.user.default} = {
191	                  imports = [
192	                    ./home/wsl.nix
193	                    ./home/identities/personal.nix
194	                  ];
195	                };
196	              }
197	            )
198	          ];
199	        };
200	
201	        # Hostname: johnny-walker
202	        johnny-walker = nixpkgs.lib.nixosSystem {
203	          specialArgs = { inherit inputs; };
204	          modules = [
205	            { nixpkgs.hostPlatform = "x86_64-linux"; }
206	            ./hosts/johnny-walker/default.nix
207	            agenix.nixosModules.default
208	            home-manager.nixosModules.home-manager
209	            (
210	              { config, ... }:
211	              {
212	                home-manager.useGlobalPkgs = true;
213	                home-manager.useUserPackages = true;
214	                home-manager.backupFileExtension = "backup";
215	                home-manager.extraSpecialArgs = { inherit inputs; };
216	                home-manager.users.${config.cosmo.user.default} = {
217	                  imports = [
218	                    ./home/desktop.nix
219	                    ./home/identities/personal.nix
220	                  ];
221	                };
222	              }
223	            )
224	          ];
225	        };
226	
227	        # Bootstrap install target for weller (hostname: weller)
228	        weller-bootstrap = mkBootstrap {
229	          hardware = ./hosts/weller/hardware.nix;
230	          disk = ./hosts/weller/disk-config.nix;
231	          hostName = "weller";
232	        };
233	
234	        # Hostname: weller (dual-boot Windows 11 + NixOS workstation)
235	        weller = nixpkgs.lib.nixosSystem {
236	          specialArgs = { inherit inputs; };
237	          modules = [
238	            { nixpkgs.hostPlatform = "x86_64-linux"; }
239	            ./hosts/weller/default.nix
240	            ./hosts/weller/disk-config.nix
241	            inputs.disko.nixosModules.disko
242	            agenix.nixosModules.default
243	            home-manager.nixosModules.home-manager
244	            (
245	              { config, ... }:
246	              {
247	                home-manager.useGlobalPkgs = true;
248	                home-manager.useUserPackages = true;
249	                home-manager.backupFileExtension = "backup";
250	                home-manager.extraSpecialArgs = { inherit inputs; };
251	                home-manager.users.${config.cosmo.user.default} = {
252	                  imports = [
253	                    ./home/desktop.nix
254	                    ./home/identities/personal.nix
255	                  ];
256	                };
257	              }
258	            )
259	          ];
260	        };
261	
262	        # Hostname: klaus-worker-0 (microVM worker for klaus agent)
263	        klaus-worker-0 = nixpkgs.lib.nixosSystem {
264	          specialArgs = { inherit inputs; };
265	          modules = [
266	            { nixpkgs.hostPlatform = "x86_64-linux"; }
267	            microvm.nixosModules.microvm
268	            ./modules/klaus-worker/default.nix
269	            {
270	              networking.hostName = "klaus-worker-0";
271	              klaus.worker = {
272	                vsockCid = 3;
273	                tapInterface = "vm-klaus-0";
274	                macAddress = "02:00:00:00:00:01";
275	              };
276	            }
277	          ];
278	        };
279	
280	      };
281	
282	      homeConfigurations = {
283	        # 1. Personal Debian (The classic)
284	        "personal" = mkHome {
285	          username = "patrick";
286	          identity = ./home/identities/personal.nix;
287	          baseModule = ./home/linux.nix;
288	        };
289	
290	        # 2. Work Debian (The new pure target)
291	        "paflynn@bushmills" = mkHome {
292	          username = "paflynn";
293	          identity = ./home/identities/work.nix;
294	          baseModule = ./home/linux.nix;
295	          homeDirectory = "/usr/local/google/home/paflynn";
296	        };
297	
298	        # 3. Personal Crostini
299	        "patrick@crostini" = mkHome {
300	          username = "patrick";
301	          identity = ./home/identities/personal.nix;
302	          baseModule = ./home/crostini.nix;
303	        };
304	
305	        # 4. Work Crostini
306	        "paflynn@crostini" = mkHome {
307	          username = "paflynn";
308	          identity = ./home/identities/work.nix;
309	          baseModule = ./home/crostini.nix;
310	        };
311	      };
312	
313	      packages.x86_64-linux = {
314	        # Expose zizmor here so CI can run it via 'nix run .#zizmor'
315	        # to avoid registry lookups and devShell hooks.
316	        zizmor = nixpkgs.legacyPackages.x86_64-linux.zizmor;
317	        klaus-worker-0 = self.nixosConfigurations.klaus-worker-0.config.microvm.declaredRunner;
318	        johnny-walker-image = nixos-generators.nixosGenerate {
319	          system = "x86_64-linux";
320	          specialArgs = { inherit inputs; };
321	          modules = [
322	            ./hosts/johnny-walker/default.nix
323	            agenix.nixosModules.default
324	            home-manager.nixosModules.home-manager
325	            (
326	              { config, ... }:
327	              {
328	                home-manager.useGlobalPkgs = true;
329	                home-manager.useUserPackages = true;
330	                home-manager.backupFileExtension = "backup";
331	                home-manager.extraSpecialArgs = { inherit inputs; };
332	                home-manager.users.${config.cosmo.user.default} = {
333	                  imports = [
334	                    ./home/desktop.nix
335	                    ./home/identities/personal.nix
336	                  ];
337	                };
338	              }
339	            )
340	          ];
341	          format = "qcow";
342	        };
343	      };
344	
345	      checks.x86_64-linux = {
346	        pre-commit-check = pre-commit-hooks.lib.x86_64-linux.run {
347	          src = ./.;
348	          hooks = {
349	            nixfmt.enable = true;
350	            detect-private-keys.enable = true;
351	            zizmor = {
352	              enable = true;
353	              name = "zizmor";
354	              entry = "${nixpkgs.legacyPackages.x86_64-linux.zizmor}/bin/zizmor .";
355	              pass_filenames = false;
356	            };
357	          };
358	        };
359	      };
360	
361	      devShells.x86_64-linux.default =
362	        let
363	          pkgs = nixpkgs.legacyPackages.x86_64-linux;
364	        in
365	        pkgs.mkShell {
366	          inherit (self.checks.x86_64-linux.pre-commit-check) shellHook;
367	          buildInputs = self.checks.x86_64-linux.pre-commit-check.enabledPackages;
368	        };
369	    };
370	}
