40	
41	  # Session variables for Wayland compatibility
42	  environment.sessionVariables = {
43	    NIXOS_OZONE_WL = "1";
44	    _JAVA_AWT_WM_NONREPARENTING = "1"; # For JetBrains IDE compatibility on Wayland
45	    XDG_SESSION_TYPE = "wayland";
46	  }
47	  // lib.optionalAttrs (builtins.elem "nvidia" (config.services.xserver.videoDrivers or [ ])) {
48	    LIBVA_DRIVER_NAME = "nvidia";
49	    GBM_BACKEND = "nvidia-drm";
50	    __GLX_VENDOR_LIBRARY_NAME = "nvidia";
51	    LD_LIBRARY_PATH = lib.mkForce (
52	      let
53	        openGLPath = "/run/opengl-driver/lib";
54	        pipewireJackPath = lib.makeLibraryPath [ pkgs.pipewire.jack ];
55	      in
56	      if config.services.pipewire.jack.enable then "${pipewireJackPath}:${openGLPath}" else openGLPath
57	    );
58	  };
59	
60	  # --- xdg portal restart policy ---
61	  # 2026-05-05 incident on classic-laddie: dbus-broker hit its per-UID byte
62	  # quota for UID 1000 and force-disconnected several user-session D-Bus
63	  # consumers. xdg-desktop-portal and xdg-document-portal exited and stayed
64	  # down because upstream nixpkgs ships them without a Restart policy.
65	  # Downstream: waybar exited two minutes later, wireplumber's session graph
66	  # went stale (Focusrite vanished from PipeWire), and the session limped
67	  # along for four days. Auto-restart turns a transient D-Bus blip back into
68	  # a transient D-Bus blip instead of a 4-day session degradation.
69	  #
70	  # StartLimit* caps prevent a genuinely broken portal (misconfig, missing
71	  # binary) from looping forever — after 5 failures in 60s systemd gives up
72	  # and surfaces the failure for manual triage.
73	  systemd.user.services =
74	    let
75	      restartPolicy = {
76	        serviceConfig = {
77	          Restart = lib.mkDefault "on-failure";
78	          RestartSec = lib.mkDefault "5s";
79	        };
80	        startLimitBurst = lib.mkDefault 5;
81	        startLimitIntervalSec = lib.mkDefault 60;
82	      };
83	    in
84	    {
85	      xdg-desktop-portal = restartPolicy;
86	      xdg-desktop-portal-gtk = restartPolicy;
87	      xdg-desktop-portal-hyprland = restartPolicy;
88	      xdg-document-portal = restartPolicy;
89	      xdg-permission-store = restartPolicy;
90	    };
91	
92	  # --- Interactive-session memory protection ---
93	  # Keep a heavy build (sudo'd, agent-launched, or manual) from wedging the
94	  # live desktop session. Scoped to desktop.nix because these settings only
95	  # make sense when system.slice is *background* work and user.slice is the
96	  # interactive session worth protecting. On a headless build worker the
97	  # opposite is true — system.slice IS the workload — so build hosts must
98	  # not import this module.
99	
100	  # Reserve a memory floor for the interactive session. Builds, services,
101	  # and containers (in system.slice) can be reclaimed before user.slice
102	  # pages are. Soft reservation — user.slice can still use more than this.
103	  systemd.slices."user".sliceConfig.MemoryMin = lib.mkDefault "8G";
104	
105	  # Make systemd-oomd's response to memory pressure aggressive enough to
106	  # actually kill runaway builds before the box wedges. The 5s averaging
107	  # window means transient spikes don't trigger kills.
108	  systemd.oomd.settings.OOM.DefaultMemoryPressureDurationSec = lib.mkDefault "5s";
109	
110	  # Aggressive OOM-kill policy targeted at system.slice only, so the
111	  # offender (a runaway build, container, or service) gets killed while
112	  # user.slice — games, Chrome, the compositor — is never touched by this
113	  # rule. mkForce because upstream nixos oomd.nix sets the limit to "80%"
114	  # at mkDefault priority — string options can't merge two equal-priority
115	  # defaults, so we have to take precedence. The "kill" mode itself is
116	  # already set as a plain assignment by upstream when enableSystemSlice
117	  # is true (see common/system.nix), so we don't need to repeat it.
118	  systemd.slices."system".sliceConfig.ManagedOOMMemoryPressureLimit = lib.mkForce "70%";
119	}
