# --- catppuccin-gtk build fixes ---
# The python 3.14 toolchain in our nixpkgs pin breaks catppuccin-gtk (the
# GTK theme in home/desktop.nix) twice over:
#  1. catppuccin 2.5.0's matplotlib extra calls mpl.style.core, removed in
#     matplotlib 3.11, so pythonImportsCheck fails.
#  2. catppuccin-gtk's own build.py passes type=bool to argparse's
#     BooleanOptionalAction, removed in python 3.14.
# Both are fixed in nixpkgs master (455d916d0c, 894acc94f6) but not yet in
# nixos-unstable — drop this overlay and the vendored patches once a flake
# update makes the build pass without them.
nixpkgs.overlays = [
  (final: prev: {
    pythonPackagesExtensions = prev.pythonPackagesExtensions ++ [
      (pyfinal: pyprev: {
        catppuccin = pyprev.catppuccin.overridePythonAttrs (old: {
          patches = (old.patches or [ ]) ++ [
            ./patches/catppuccin-matplotlib-3.11.patch
          ];
        });
      })
    ];

    catppuccin-gtk = prev.catppuccin-gtk.overrideAttrs (old: {
      patches = (old.patches or [ ]) ++ [
        ./patches/catppuccin-gtk-python-3.14.patch
      ];
    });
  })
];

